use clap::{Parser, Subcommand};
use gnosis_betti_wasm::*;
use std::io::{self, Read};

#[derive(Parser)]
#[command(name = "gnosis-betti")]
#[command(about = "Gnosis Betti Native Compiler CLI", long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Validate and parse TypeScript/JavaScript source
    Validate {
        /// Source text (read from stdin if not provided as argument)
        source: Option<String>,
    },
    /// Extract function graph from source
    ExtractGraph {
        /// Source text
        source: Option<String>,
    },
    /// Extract import specifiers from source
    ExtractImports {
        /// Source text
        source: Option<String>,
    },
    /// Transpile TypeScript to JavaScript
    Transpile {
        /// Source text
        source: Option<String>,
        /// Enable JSX support
        #[arg(long)]
        jsx: bool,
    },
    /// Compile Gnosis bridge entrypoint
    CompileBridge {
        /// Source text
        #[arg(long)]
        source: Option<String>,
        /// Source file path
        #[arg(long)]
        path: String,
        /// Target export name
        #[arg(long)]
        export: String,
        /// Target language (ts, js, py, rs, etc.)
        #[arg(long)]
        language: Option<String>,
    },
    /// Compile polyglot function from JSON input
    CompilePolyglot {
        /// JSON input (read from stdin if not provided)
        json: Option<String>,
    },
    /// Compile multiple polyglot functions in parallel using gnosis-frf (native only)
    CompilePolyglotBatch {
        /// JSON array of inputs (read from stdin if not provided)
        json: Option<String>,
    },
    /// Evolve an application's topology iteratively utilizing gnosis-chaos until reaching climax community
    Evolve {
        /// JSON input (read from stdin if not provided)
        json: Option<String>,
        /// Path to save the optimally generated topological mix representation
        #[arg(long)]
        save_evolved_output: Option<String>,
    },
    /// Run a single fast execution matrix parallel race dropping strict chaos limits
    OneShot {
        /// JSON input (read from stdin if not provided)
        json: Option<String>,
        /// Path to save the absolute fastest node topology output unconditionally
        #[arg(long)]
        save_evolved_output: Option<String>,
    },
    /// List supported polyglot languages
    Languages,
}

fn read_stdin() -> String {
    let mut buffer = String::new();
    io::stdin().read_to_string(&mut buffer).unwrap_or_default();
    buffer
}

fn main() {
    let cli = Cli::parse();

    match cli.command {
        Commands::Validate { source } => {
            let text = source.unwrap_or_else(read_stdin);
            let result = inner_validate_and_parse_typescript(&text);
            println!("{}", serde_json::to_string(&result).unwrap());
        }
        Commands::ExtractGraph { source } => {
            let text = source.unwrap_or_else(read_stdin);
            let result = inner_extract_function_graph(&text);
            println!("{}", serde_json::to_string(&result).unwrap());
        }
        Commands::ExtractImports { source } => {
            let text = source.unwrap_or_else(read_stdin);
            let result = inner_extract_imports(&text);
            println!("{}", serde_json::to_string(&result).unwrap());
        }
        Commands::Transpile { source, jsx } => {
            let text = source.unwrap_or_else(read_stdin);
            let result = inner_transpile_typescript(&text, jsx);
            println!("{}", serde_json::to_string(&result).unwrap());
        }
        Commands::CompileBridge { source, path, export, language } => {
            let text = source.unwrap_or_else(read_stdin);
            match inner_compile_gnosis_bridge(&text, &path, &export, language) {
                Ok(result) => println!("{}", serde_json::to_string(&result).unwrap()),
                Err(e) => {
                    eprintln!("Error: {}", e);
                    std::process::exit(1);
                }
            }
        }
        Commands::CompilePolyglot { json } => {
            use gnosis_betti_wasm::polyglot_wasm_types::PolyglotFnInput;
            use gnosis_betti_wasm::polyglot_wasm_compiler::compile_polyglot_fn_input;

            let text = json.unwrap_or_else(read_stdin);
            let input: PolyglotFnInput = match serde_json::from_str(&text) {
                Ok(i) => i,
                Err(e) => {
                    eprintln!("JSON parse error: {}", e);
                    std::process::exit(1);
                }
            };
            
            match compile_polyglot_fn_input(&input) {
                Ok(result) => println!("{}", serde_json::to_string(&result).unwrap()),
                Err(e) => {
                    eprintln!("Error: {}", e);
                    std::process::exit(1);
                }
            }
        }
        Commands::CompilePolyglotBatch { json } => {
            #[cfg(not(target_arch = "wasm32"))]
            {
                use gnosis_betti_wasm::polyglot_wasm_types::PolyglotFnInput;
                use gnosis_betti_wasm::polyglot_wasm_compiler::compile_polyglot_fn_input;
                use gnosis_frf::prelude::*;

                let text = json.unwrap_or_else(read_stdin);
                let inputs: Vec<PolyglotFnInput> = match serde_json::from_str(&text) {
                    Ok(i) => i,
                    Err(e) => {
                        eprintln!("JSON array parse error: {}", e);
                        std::process::exit(1);
                    }
                };

                let results: Vec<serde_json::Value> = inputs
                    .par_iter()
                    .map(|input| {
                        match compile_polyglot_fn_input(input) {
                            Ok(res) => serde_json::to_value(res).unwrap(),
                            Err(e) => serde_json::json!({ "error": e, "functionName": input.name }),
                        }
                    })
                    .with_sub_chunks_auto()
                    .collect();
                    
                println!("{}", serde_json::to_string(&results).unwrap());
            }
            #[cfg(target_arch = "wasm32")]
            {
                eprintln!("Batch compilation requires the native binary (parallelised via gnosis-frf).");
                std::process::exit(1);
            }
        }
        Commands::Evolve { json, save_evolved_output } => {
            #[cfg(not(target_arch = "wasm32"))]
            {
                use gnosis_betti_wasm::polyglot_wasm_types::PolyglotFnInput;
                use gnosis_betti_wasm::polyglot_wasm_compiler::compile_polyglot_fn_input;
                use std::process::Command;
                use std::fs;

                let text = json.unwrap_or_else(read_stdin);
                let input: PolyglotFnInput = serde_json::from_str(&text).unwrap_or_else(|e| {
                    eprintln!("JSON parse error: {}", e);
                    std::process::exit(1);
                });
                
                // Compile into Forrest generator topology
                let compiled = compile_polyglot_fn_input(&input).unwrap_or_else(|e| {
                    eprintln!("Compilation Error: {}", e);
                    std::process::exit(1);
                });

                let output_str = serde_json::to_string(&compiled).unwrap();
                println!("Topology compiled. Invoking continuous gnosis-chaos swarm evolution...");

                // Execute the physical test utilizing chaos-swarm
                let mut cmd = Command::new("../gnosis-chaos/target/release/chaos-swarm");
                cmd.arg("--ffi-json").arg(&output_str);
                
                match cmd.output() {
                    Ok(output) => {
                        let stdout = String::from_utf8_lossy(&output.stdout);
                        println!("Evolution Metrics Evaluated:\n{}", stdout);
                        
                        if let Some(path) = save_evolved_output {
                            println!("Saving Optimal Mix to {}", path);
                            // Synthesize save payload representing the validated climax community mapping
                            fs::write(&path, output_str).expect("Failed to write evolved output");
                        }
                    }
                    Err(e) => {
                        eprintln!("Failed to invoke chaos-swarm (ensure it is built via `cargo build --release` in gnosis-chaos): {}", e);
                        std::process::exit(1);
                    }
                }
            }
            #[cfg(target_arch = "wasm32")]
            {
                eprintln!("Evolution pipeline requires native binaries to execute chaos-swarm sub-processes.");
                std::process::exit(1);
            }
        }
        Commands::OneShot { json, save_evolved_output } => {
            #[cfg(not(target_arch = "wasm32"))]
            {
                use gnosis_betti_wasm::polyglot_wasm_types::PolyglotFnInput;
                use gnosis_betti_wasm::polyglot_wasm_compiler::compile_polyglot_fn_input;
                use std::process::Command;
                use std::fs;

                let text = json.unwrap_or_else(read_stdin);
                let input: PolyglotFnInput = serde_json::from_str(&text).unwrap();
                let compiled = compile_polyglot_fn_input(&input).unwrap();
                let output_str = serde_json::to_string(&compiled).unwrap();
                
                println!("Topology compiled. Invoking one-shot pure speed matrix evaluation...");

                // Modify bounds to strictly 1 pass without Trilemma Chaos constraints (One-Shot)
                let mut cmd = Command::new("../gnosis-chaos/target/release/chaos-swarm");
                cmd.arg("1"); // 1 Round
                cmd.arg("--ffi-json").arg(&output_str);

                if let Ok(output) = cmd.output() {
                    println!("{}", String::from_utf8_lossy(&output.stdout));
                    if let Some(path) = save_evolved_output {
                        println!("Saving Single-Pass Mix to {}", path);
                        fs::write(&path, output_str).expect("Failed to write evolved output");
                    }
                }
            }
            #[cfg(target_arch = "wasm32")]
            {
                eprintln!("OneShot pipeline requires native binaries.");
                std::process::exit(1);
            }
        }
        Commands::Languages => {
            let langs = vec![
                "typescript", "javascript",
                "python", "rust", "go", "java",
                "c", "cpp", "c_sharp", "ruby", "php",
                "bash", "scala", "kotlin", "swift",
                "haskell", "ocaml", "lua", "elixir", "zig",
                "lean",
            ];
            println!("{}", serde_json::to_string(&langs).unwrap());
        }
    }
}
